-- Add new schema named "bronze_history"
CREATE SCHEMA IF NOT EXISTS "bronze_history";
-- Create "jenkins_build_repos_history" table
CREATE TABLE "bronze_history"."jenkins_build_repos_history" (
  "history_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "build_history_id" bigint NOT NULL,
  "valid_from" timestamptz NOT NULL,
  "valid_to" timestamptz NULL,
  "repo_url" character varying NULL,
  "branch" character varying NULL,
  "commit_sha" character varying NULL,
  PRIMARY KEY ("history_id")
);
-- Create index "bronzehistoryjenkinsbuildrepo_build_history_id" to table: "jenkins_build_repos_history"
CREATE INDEX "bronzehistoryjenkinsbuildrepo_build_history_id" ON "bronze_history"."jenkins_build_repos_history" ("build_history_id");
-- Create index "bronzehistoryjenkinsbuildrepo_valid_from" to table: "jenkins_build_repos_history"
CREATE INDEX "bronzehistoryjenkinsbuildrepo_valid_from" ON "bronze_history"."jenkins_build_repos_history" ("valid_from");
-- Create index "bronzehistoryjenkinsbuildrepo_valid_to" to table: "jenkins_build_repos_history"
CREATE INDEX "bronzehistoryjenkinsbuildrepo_valid_to" ON "bronze_history"."jenkins_build_repos_history" ("valid_to");
-- Create "jenkins_builds_history" table
CREATE TABLE "bronze_history"."jenkins_builds_history" (
  "history_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "job_history_id" bigint NOT NULL,
  "valid_from" timestamptz NOT NULL,
  "valid_to" timestamptz NULL,
  "build_number" bigint NOT NULL,
  "result" character varying NULL,
  "timestamp" timestamptz NULL,
  "duration_ms" bigint NOT NULL DEFAULT 0,
  "version" character varying NULL,
  "check_code_enabled" boolean NOT NULL DEFAULT false,
  PRIMARY KEY ("history_id")
);
-- Create index "bronzehistoryjenkinsbuild_job_history_id" to table: "jenkins_builds_history"
CREATE INDEX "bronzehistoryjenkinsbuild_job_history_id" ON "bronze_history"."jenkins_builds_history" ("job_history_id");
-- Create index "bronzehistoryjenkinsbuild_valid_from" to table: "jenkins_builds_history"
CREATE INDEX "bronzehistoryjenkinsbuild_valid_from" ON "bronze_history"."jenkins_builds_history" ("valid_from");
-- Create index "bronzehistoryjenkinsbuild_valid_to" to table: "jenkins_builds_history"
CREATE INDEX "bronzehistoryjenkinsbuild_valid_to" ON "bronze_history"."jenkins_builds_history" ("valid_to");
-- Create "jenkins_jobs_history" table
CREATE TABLE "bronze_history"."jenkins_jobs_history" (
  "history_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "valid_from" timestamptz NOT NULL,
  "valid_to" timestamptz NULL,
  "collected_at" timestamptz NOT NULL,
  "first_collected_at" timestamptz NOT NULL,
  "resource_id" character varying NOT NULL,
  "job_class" character varying NULL,
  "project_type" character varying NULL,
  "is_buildable" boolean NOT NULL DEFAULT false,
  "last_build_number" bigint NOT NULL DEFAULT 0,
  "last_build_time" timestamptz NULL,
  PRIMARY KEY ("history_id")
);
-- Create index "bronzehistoryjenkinsjob_collected_at" to table: "jenkins_jobs_history"
CREATE INDEX "bronzehistoryjenkinsjob_collected_at" ON "bronze_history"."jenkins_jobs_history" ("collected_at");
-- Create index "bronzehistoryjenkinsjob_resource_id_valid_from" to table: "jenkins_jobs_history"
CREATE INDEX "bronzehistoryjenkinsjob_resource_id_valid_from" ON "bronze_history"."jenkins_jobs_history" ("resource_id", "valid_from");
-- Create index "bronzehistoryjenkinsjob_valid_to" to table: "jenkins_jobs_history"
CREATE INDEX "bronzehistoryjenkinsjob_valid_to" ON "bronze_history"."jenkins_jobs_history" ("valid_to");
